msg.url = "http://35.244.85.126/trend";
msg.headers = {
  "Content-Type": "application/json"
};
msg.method = "POST";
msg.payload = {
  product: msg.payload.product,
  startDate: msg.payload.startDate,
  endDate: msg.payload.endDate
};

msg.topic = "trend";

return msg;

msg.url = "http://35.244.85.126/sentiment";
msg.headers = {
  "Content-Type": "application/json"
};
msg.method = "POST";
msg.payload = {
  product: msg.payload.product,
  videoCount: msg.payload.videoCount,
  commentCount: msg.payload.commentCount
};

msg.topic = "sentiment";

return msg;

const productName = msg.payload.product || msg.payload.productName;

msg.url = `http://35.244.85.126/products/${encodeURIComponent(productName)}`;
msg.method = "GET";
msg.headers = {
  "Content-Type": "application/json"
};

msg.payload = null;

msg.topic = "inventory";

return msg;

msg.trend_summary = msg.payload.trend.trend;
msg.payload = msg.trend_summary;

msg.topic = "trend_param";
return msg;

msg.sentiment_summary = msg.payload.sentiment.summary; 
msg.payload = msg.sentiment_summary;
msg.topic = "sentiment_param"
return msg;

const records = msg.payload.inventory;
const input = msg.payload.input || {};

if (!Array.isArray(records)) {
  msg.payload.inventory = { error: "Expected array of inventory records" };
  return msg;
}

let totalCOGS = 0;
let totalBegin = 0;
let totalEnd = 0;
let totalTarget = 0;
let periods = [];

records.forEach(record => {
  const begin = record["Beginning Inventory"] || 0;
  const end = record["Ending Inventory"] || 0;
  const cogs = record["COGS"] || 0;
  const target = record["Target Turnover"] || 0;

  totalCOGS += cogs;
  totalBegin += begin;
  totalEnd += end;
  totalTarget += target;
  periods.push(record.period);
});

const avgInventory = (totalBegin + totalEnd) / (2 * records.length);
const turnover = avgInventory > 0 ? totalCOGS / avgInventory : 0;
const avgTarget = totalTarget / records.length;

const sortedPeriods = periods.sort();
const summary = {
  "Start Period": sortedPeriods[0],
  "End Period": sortedPeriods[sortedPeriods.length - 1],
  "Total COGS": totalCOGS,
  "Average Inventory": Number(avgInventory.toFixed(2)),
  "Inventory Turnover": Number(turnover.toFixed(2)),
  "Average Target Turnover": Number(avgTarget.toFixed(2)),
  "Turnover Gap": Number((turnover - avgTarget).toFixed(2))
};


msg.payload = [summary];
msg.inventory_summary = msg.payload;
msg.topic = "inventory_param";

return msg;

const params = msg.geminiParams || {};

msg.payload = {
    contents: [
        {
            parts: [
                {
                    text: 
                        `Here is overall analytics for "${params.product}" between ${params.startDate} and ${params.endDate}.\n\n` +
                        `Overall Analysis:\n- ${params.sentimentSummary}\n- ${params.trendSummary}\n- ${params.inventoryTurnoverSummary}\n\n` +
                        `Provide your recommendation on stocking decision as an inventory manager.\n\n` +
                        `Use text based response. No markdown, bullet points or formatting. Use a dash instead.\n` +  
                        `1. Analysis Results: Rephrase analysis with enhance readability\n` +
                        `2. Recommendation: Stock Action: Increase or Hold or Reduce\n` +
                        `3. Justification: [Provide 2–3 concise bullet points explaining your recommendation]\n\n` +
                        `4. Estimated Units:\n [Provide the result. Then a concise explanation of calculation. Use the turnover gap to estimate whether stock should be increased or reduced, and by how much (in units). Assume current inventory is based on average inventory value.]\n\n` +
                        `5. Important Considerations\n* [Consideration 1]\n* [Consideration 2]\n* [Consideration 3]\n\n` +
                        `Disclaimer\nThis is a preliminary recommendation based on provided data.`

                }
            ]
        }
    ]
};

return msg;

try {
    const text = msg.payload?.candidates?.[0]?.content?.parts?.[0]?.text;

    if (!text) {
        throw new Error("No text response found in Gemini output");
    }

    msg.payload = text;               // Main response output
    msg.gemini_response = text;       // Optional backup or for logging
} catch (err) {
    msg.payload = {
        error: "Failed to retrieve Gemini text response",
        details: err.message
    };
    msg.gemini_response = null;
}

return msg;

const input = msg.payload.input || {};
const trend = msg.payload.trend_param || {};
const sentiment = msg.payload.sentiment_param || {};
const inventory = msg.payload.inventory_param?.[0] || {}; // Use the first and only summary object

msg.geminiParams = {
  product: input.product,
  startDate: input.startDate,
  endDate: input.endDate,

  trendSummary: 
    `Google Trend interest overtime: from ${trend.start_value} to ${trend.end_value} (${trend.percent_change}%, ${trend.trend})`,

  sentimentSummary: 
    `YouTube Comment Sentiment: ${sentiment.clearly_positive} positive, ${sentiment.clearly_negative} negative, ` +
    `${sentiment.neutral} neutral, ${sentiment.mixed} mixed.`,

  inventoryTurnoverSummary: 
    `Historical Inventory Turnover (${inventory["Start Period"]} to ${inventory["End Period"]}):\n` +
    `- Total COGS: ${inventory["Total COGS"]}\n` +
    `- Average Inventory: ${inventory["Average Inventory"]}\n` +
    `- Inventory Turnover: ${inventory["Inventory Turnover"]}\n` +
    `- Target Turnover: ${inventory["Average Target Turnover"]}\n` +
    `- Turnover Gap: ${inventory["Turnover Gap"] > 0 ? "+" : ""}${inventory["Turnover Gap"]}`
};

return msg;

function formatDate(dateInput) {
    const date = new Date(dateInput);
    const yyyy = date.getFullYear();
    const mm = String(date.getMonth() + 1).padStart(2, '0');
    const dd = String(date.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
}

const product = encodeURIComponent(msg.payload.product);
const startDate = formatDate(msg.payload.startDate);
const endDate = formatDate(msg.payload.endDate);
const date = `${startDate} ${endDate}`;
const apiKeyTruc = "cd154b4dc6a28ea60900b8d5d55dd85510d4ce67e2883e9bd9fdecb35c156efa";
const apiKeyLinh = "1b31b5d2bfb359824af5cc3fab4aa33a3164be0c31c03792575680f9ba3e4fe0";

msg.method = "GET";
msg.url = `https://serpapi.com/search.json?engine=google_trends&q=${product}&geo=AU&date=${encodeURIComponent(date)}&data_type=TIMESERIES&api_key=${apiKeyLinh}`;

return msg;

const timeline = msg.payload;

if (!Array.isArray(timeline) || timeline.length < 2) {
    msg.trend = { error: "Not enough timeline data" };
    return msg;
}

// Extract numeric trend values from extracted_value field
const extractValue = entry =>
    entry?.values?.[0]?.extracted_value ?? null;

const start = extractValue(timeline[0]);
const end = extractValue(timeline[timeline.length - 1]);

if (typeof start !== "number" || typeof end !== "number") {
    msg.trend = { error: "Invalid trend data" };
    return msg;
}

const percentChange = ((end - start) / (start || 1)) * 100;
const trend = percentChange > 0 ? "upward" : (percentChange < 0 ? "downward" : "stable");

msg.trend = {
    start_value: start,
    end_value: end,
    percent_change: parseFloat(percentChange.toFixed(2)),
    trend
};

return msg;

msg.payload = {
    trend: msg.trend,
    timeline: msg.payload
};
return msg;

let product = '';
let videoCount = 5; //default max value
let commentCount = 50; // default max value

if (typeof msg.payload === 'object') {
  product = msg.payload.product || msg.payload.topic || '';
  videoCount = msg.payload.videoCount || videoCount;
  commentCount = msg.payload.commentCount || commentCount;
}

if (!product) {
  node.error('No product provided', msg);
}

msg.topic = product;
msg.videoCount = videoCount;
msg.commentCount = commentCount;

return msg;

const apiKey = 'AIzaSyB5Akr38qW4F6Jl-J92E0JDh_AjDTn5ivA';
// const query = encodeURIComponent(msg.topic);
const query = encodeURIComponent(`${msg.topic} review`);
const url = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${query}&type=video&maxResults=${msg.videoCount}&key=${apiKey}`;
msg.method = 'GET';
msg.url = url;
return msg;

const comments = msg.payload.items || [];
msg.payload = comments.map(item => ({
  text: item.snippet.topLevelComment.snippet.textOriginal
}));

msg._req = msg._req;
msg._res = msg._res;

return msg;

const score = msg.sentiment.score || 0;
const magnitude = msg.sentiment.magnitude || 0;

msg.payload = {
  comment: msg.payload,
  sentiment_score: score,
  sentiment_magnitude: magnitude
};

return msg;

const videos = msg.payload.items || [];
const apiKey = 'AIzaSyB5Akr38qW4F6Jl-J92E0JDh_AjDTn5ivA';

if (videos.length === 0) {
    msg.payload = [];
    return [null, msg];
}

const messages = videos.map(item => ({
    method: 'GET',
    url: `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${item.id.videoId}&maxResults=${msg.commentCount}&key=${apiKey}`,
}));

return [messages, null];

// Flatten the joined array-of-arrays result
const results = msg.payload.flat();

// Sentiment category counters
let summary = {
    clearly_positive: 0,
    clearly_negative: 0,
    neutral: 0,
    mixed: 0
};

// Categorize each entry and add to summary
const categorized = results.map(entry => {
    const score = entry.sentiment_score;
    const magnitude = entry.sentiment_magnitude;

    let sentiment;

    if (score >= 0.25) {
        sentiment = 'clearly_positive';
    } else if (score <= -0.25) {
        sentiment = 'clearly_negative';
    } else if (Math.abs(score) < 0.15 && magnitude >= 2) {
        sentiment = 'mixed';
    } else {
        sentiment = 'neutral';
    }

    summary[sentiment]++;
    return { ...entry, sentiment };
});

// Final payload
msg.payload = {
    summary,
    chartData: Object.entries(summary).map(([label, value]) => ({ label, value })),
    comments: categorized
};

return msg;

const productName = msg.product_name;
const products = msg.payload;

if (products && products[productName]) {
    msg.payload = products[productName]; // Return the array for the specified product
    msg.statusCode = 200;
} else {
    msg.payload = { error: `Product '${productName}' not found` };
    msg.statusCode = 404;
}

return msg;

msg.product_name = msg.req.params.product_name.replace(/%20/g, ' ');
msg.new_record = msg.payload; // Store the incoming record
return msg;

const productName = msg.product_name;
const newRecord = msg.new_record;
let existingData = msg.payload;

// Validate new record
if (!newRecord.id || !newRecord.period || !newRecord['Beginning Inventory'] || !newRecord.COGS || !newRecord['Ending Inventory'] || !newRecord.Sales || !newRecord['Target Turnover']) {
    msg.payload = { error: 'Invalid record format. All fields (id, period, Beginning Inventory, COGS, Ending Inventory, Sales, Target Turnover) are required' };
    msg.statusCode = 400;
    return msg;
}

// If no existing data, initialize as empty array
if (!existingData || existingData === null) {
    existingData = [];
}

// Check for duplicate ID
if (Array.isArray(existingData) && existingData.some(record => record.id === newRecord.id)) {
    msg.payload = { error: `Record with id '${newRecord.id}' already exists for product '${productName}'` };
    msg.statusCode = 409;
    return msg;
}

// Append new record
existingData.push(newRecord);
msg.payload = existingData;
msg.url = 'https://connect-f885d-default-rtdb.asia-southeast1.firebasedatabase.app/products/' + encodeURIComponent(productName) + '.json?auth=RqgAoe4IuML15ztQStVDPpEERh4XeOkseQSVoRdr';
msg.method = 'PUT';

return msg;

if (msg.statusCode === 200) {
    msg.payload = { message: 'Record uploaded successfully', data: msg.payload };
} else {
    msg.payload = { error: 'Failed to upload record', statusCode: msg.statusCode, response: msg.payload };
    msg.statusCode = msg.statusCode || 500;
}
return msg;
